module gray_counter_core #(
    parameter integer WIDTH = 4
) (
    input  logic             clk,
    input  logic             rst_n,
    input  logic             enable,
    input  logic             clear,
    output logic [WIDTH-1:0] gray_value,
    output logic [WIDTH-1:0] bin_value,
    output logic             done
);

    localparam [2:0] ST_RESET      = 3'd0;
    localparam [2:0] ST_IDLE       = 3'd1;
    localparam [2:0] ST_RUN        = 3'd2;
    localparam [2:0] ST_WRAP_PULSE = 3'd3;
    localparam [2:0] ST_CLEARED    = 3'd4;

    logic [WIDTH-1:0] gray_state;
    logic [WIDTH-1:0] bin_state;
    logic             done_state;

    logic [WIDTH-1:0] bin_next;
    logic [WIDTH-1:0] gray_next;
    logic             wrap_detect;

    logic [2:0]       fsm_state;
    logic [2:0]       fsm_next;

    logic [WIDTH-1:0] bin_decode_stage;
    logic [WIDTH-1:0] bin_decode_gray;

    logic [WIDTH-1:0] width_all_ones;
    assign width_all_ones = {WIDTH{1'b1}};

    assign bin_next    = bin_state + {{(WIDTH-1){1'b0}}, 1'b1};
    assign gray_next   = bin_next ^ (bin_next >> 1);
    assign wrap_detect = (bin_state == width_all_ones) ? 1'b1 : 1'b0;

    always @(*) begin
        bin_decode_stage = gray_state;
        bin_decode_stage = bin_decode_stage ^ (bin_decode_stage >> 1);
        bin_decode_stage = bin_decode_stage ^ (bin_decode_stage >> 2);
        bin_decode_stage = bin_decode_stage ^ (bin_decode_stage >> 4);
        bin_decode_stage = bin_decode_stage ^ (bin_decode_stage >> 8);
        bin_decode_stage = bin_decode_stage ^ (bin_decode_stage >> 16);
        bin_decode_gray  = bin_decode_stage;
    end

    always @(*) begin
        fsm_next = fsm_state;
        case (fsm_state)
            ST_RESET: begin
                if (rst_n) begin
                    fsm_next = ST_IDLE;
                end
            end
            ST_IDLE: begin
                if (clear) begin
                    fsm_next = ST_CLEARED;
                end else if (enable) begin
                    if (wrap_detect) begin
                        fsm_next = ST_WRAP_PULSE;
                    end else begin
                        fsm_next = ST_RUN;
                    end
                end
            end
            ST_RUN: begin
                if (clear) begin
                    fsm_next = ST_CLEARED;
                end else if (!enable) begin
                    fsm_next = ST_IDLE;
                end else if (wrap_detect) begin
                    fsm_next = ST_WRAP_PULSE;
                end else begin
                    fsm_next = ST_RUN;
                end
            end
            ST_WRAP_PULSE: begin
                if (clear) begin
                    fsm_next = ST_CLEARED;
                end else if (enable) begin
                    fsm_next = ST_RUN;
                end else begin
                    fsm_next = ST_IDLE;
                end
            end
            ST_CLEARED: begin
                if (clear) begin
                    fsm_next = ST_CLEARED;
                end else begin
                    fsm_next = ST_IDLE;
                end
            end
            default: begin
                fsm_next = ST_RESET;
            end
        endcase
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            gray_state <= {WIDTH{1'b0}};
            bin_state  <= {WIDTH{1'b0}};
            done_state <= 1'b0;
            fsm_state  <= ST_RESET;
        end else begin
            fsm_state <= fsm_next;

            if (clear) begin
                gray_state <= {WIDTH{1'b0}};
                bin_state  <= {WIDTH{1'b0}};
                done_state <= 1'b0;
            end else if (enable) begin
                gray_state <= gray_next;
                bin_state  <= bin_next;
                if (wrap_detect) begin
                    done_state <= 1'b1;
                end else begin
                    done_state <= 1'b0;
                end
            end else begin
                gray_state <= gray_state;
                bin_state  <= bin_state;
                done_state <= 1'b0;
            end
        end
    end

    assign gray_value = gray_state;
    assign bin_value  = bin_decode_gray;
    assign done       = done_state;

endmodule

